// Convert HubSpot company records into Ramsisa locations[] payloads — one per rep.
//
// Selection: only companies with `ramsisa_include` truthy are scheduled.
// Grouping: companies are grouped by `hubspot_owner_id` (the standard HubSpot
//   owner field). Each owner becomes one Ramsisa /schedules/generate/ call —
//   this matches the API's per-rep shape: one call = one rep's schedule.
//   Companies with `ramsisa_include=true` but no HubSpot owner are skipped.
//
// Field names match the Ramsisa API exactly (https://schedule.ramsisa.com/docs/api-reference/):
//   id, name, tier, territory, latitude, longitude, available_from?, available_to?, available_days?
//
// HubSpot custom properties expected on the Company object:
//   ramsisa_include (bool), ramsisa_tier, ramsisa_territory,
//   ramsisa_latitude, ramsisa_longitude (or `ramsisa_lat` / `ramsisa_lng` as aliases),
//   ramsisa_available_from?, ramsisa_available_to?, ramsisa_available_days?
//
// `territory` is a sub-area within ONE rep's coverage (used by Ramsisa to keep
// day-routes tight). It is NOT how reps are partitioned — that's the owner.
//
// available_days accepts comma, semicolon, whitespace, or pipe as separators.

const DAY_ALIASES = {
  sat: 'saturday', sun: 'sunday', mon: 'monday', tue: 'tuesday', wed: 'wednesday', thu: 'thursday', fri: 'friday',
};

function prop(record, key) {
  // HubSpot v2 records expose properties either at record.properties[key] or record[key].
  if (record.properties && key in record.properties) return record.properties[key];
  return record[key];
}

function truthy(v) {
  if (v == null) return false;
  if (typeof v === 'boolean') return v;
  const s = String(v).trim().toLowerCase();
  return s === 'true' || s === 'yes' || s === '1';
}

const byOwner = new Map();
const skipped = [];

for (const item of $input.all()) {
  const c = item.json;
  if (!truthy(prop(c, 'ramsisa_include'))) continue;

  const id = String(c.id ?? c.companyId ?? prop(c, 'hs_object_id') ?? '').trim();
  if (!id) { skipped.push({ reason: 'missing HubSpot id', record: c }); continue; }

  const ownerId = String(prop(c, 'hubspot_owner_id') ?? '').trim();
  if (!ownerId) {
    skipped.push({ reason: 'company has no HubSpot owner — assign one to schedule it', id });
    continue;
  }

  const tier = String(prop(c, 'ramsisa_tier') ?? '').trim().toUpperCase();
  const territory = String(prop(c, 'ramsisa_territory') ?? '').trim();
  const latitude = Number(prop(c, 'ramsisa_latitude') ?? prop(c, 'ramsisa_lat'));
  const longitude = Number(prop(c, 'ramsisa_longitude') ?? prop(c, 'ramsisa_lng'));

  if (!tier || !territory || Number.isNaN(latitude) || Number.isNaN(longitude)) {
    skipped.push({ reason: 'missing required ramsisa_* properties', id, tier, territory, latitude, longitude });
    continue;
  }

  const loc = {
    id,
    name: String(prop(c, 'name') ?? id),
    tier,
    territory,
    latitude,
    longitude,
  };

  const from = prop(c, 'ramsisa_available_from');
  const to = prop(c, 'ramsisa_available_to');
  const days = prop(c, 'ramsisa_available_days');
  if (from) loc.available_from = String(from);
  if (to) loc.available_to = String(to);
  if (days) {
    loc.available_days = String(days)
      .split(/[,;|\s]+/)
      .filter(Boolean)
      .map((s) => s.toLowerCase())
      .map((s) => DAY_ALIASES[s] || s);
  }

  if (!byOwner.has(ownerId)) byOwner.set(ownerId, []);
  byOwner.get(ownerId).push(loc);
}

if (byOwner.size === 0) {
  throw new Error(
    `No HubSpot companies eligible for scheduling (${skipped.length} skipped). ` +
    'Each company needs ramsisa_include=true, ramsisa_tier, ramsisa_territory, ' +
    'ramsisa_latitude/longitude, AND a HubSpot owner.'
  );
}

// Emit one item per rep. The Ramsisa: Generate Schedule node downstream
// fires once per item by default — one /schedules/generate/ call per rep.
return Array.from(byOwner.entries()).map(([owner_id, locations]) => ({
  json: {
    owner_id,
    locations,
    location_count: locations.length,
    skipped_count: skipped.length,
  },
}));
